import { expect } from "chai";
import capitalize from "../src/capitalize.js";

describe("capitalize", () => {
  it("should capitalize the first letter of a string", () => {
    expect(capitalize("hello world")).to.equal("Hello world");
  });

  it("should leave first letter capitalized if already uppercase", () => {
    expect(capitalize("Hello")).to.equal("Hello");
  });

  it("should handle empty string", () => {
    expect(capitalize("")).to.equal("");
  });
});

import isSymbol from './isSymbol.js'

/** Used as references for various `Number` constants. */
const INFINITY = 1 / 0

/**
 * Converts `value` to a string. An empty string is returned for `null`
 * and `undefined` values. The sign of `-0` is preserved.
 *
 * @since 4.0.0
 * @category Lang
 * @param {*} value The value to convert.
 * @returns {string} Returns the converted string.
 * @example
 *
 * toString(null)
 * // => ''
 *
 * toString(-0)
 * // => '-0'
 *
 * toString([1, 2, 3])
 * // => '1,2,3'
 */
function toString(value) {

  // Exit early for strings to avoid a performance hit in some environments.
  if (typeof value === 'string') {
    return value
  }
  if (Array.isArray(value)) {
    // Recursively convert values (susceptible to call stack limits).
    return `${value.map((other) => other == null ? other : toString(other))}`
  }
  if (isSymbol(value)) {
    return value.toString()
  }
  const result = `${value}`
  return (result == '0' && (1 / value) == -INFINITY) ? '-0' : result
}

export default toString

import { expect } from "chai";
import chunk from "../src/chunk.js";

describe("chunk", () => {
  const arr = [1, 2, 3, 4, 5];

  it("should split array into chunks of given size", () => {
    expect(chunk(arr, 2)).to.deep.equal([[1, 2], [3, 4], [5]]);
  });

  it("should handle size larger than array length", () => {
    expect(chunk(arr, 10)).to.deep.equal([[1, 2, 3, 4, 5]]);
  });

  it("should handle size 0 or negative", () => {
    expect(chunk(arr, 0)).to.deep.equal([]);
    expect(chunk(arr, -1)).to.deep.equal([]);
  });

  it("should handle empty array", () => {
    expect(chunk([], 2)).to.deep.equal([]);
  });
});

import isObject from './isObject.js'
import isSymbol from './isSymbol.js'

/** Used as references for various `Number` constants. */
const NAN = 0 / 0

/** Used to match leading and trailing whitespace. */
const reTrim = /^\s+|\s+$/g

/** Used to detect bad signed hexadecimal string values. */
const reIsBadHex = /^[-+]0x[0-9a-f]+$/i

/** Used to detect binary string values. */
const reIsBinary = /^0b[01]+$/i

/** Used to detect octal string values. */
const reIsOctal = /^0o[0-7]+$/i

/** Built-in method references without a dependency on `root`. */
const freeParseInt = parseInt

/**
 * Converts `value` to a number.
 *
 * @since 4.0.0
 * @category Lang
 * @param {*} value The value to process.
 * @returns {number} Returns the number.
 * @see isInteger, toInteger, isNumber
 * @example
 *
 * toNumber(3.2)
 * // => 3.2
 *
 * toNumber(Number.MIN_VALUE)
 * // => 5e-324
 *
 * toNumber(Infinity)
 * // => Infinity
 *
 * toNumber('3.2')
 * // => 3.2
 */
function toNumber(value) {
  if (typeof value === 'number') {
    return value
  }
  if (isSymbol(value)) {
    return NAN
  }
  if (isObject(value)) {
    const other = typeof value.valueOf === 'function' ? value.valueOf() : value
    value = isObject(other) ? `${other}` : other
  }
  if (typeof value !== 'string') {
    return value === 0 ? value : +value
  }
  value = value.replace(reTrim, '')
  const isBinary = reIsBinary.test(value)
  return (isBinary || reIsOctal.test(value))
    ? freeParseInt(value.slice(2), isBinary ? 2 : 8)
    : (reIsBadHex.test(value) ? NAN : +value)
}

export default toNumber

import { expect } from "chai";
import isObject from "../src/isObject.js";

describe("isObject", () => {
  it("should return true for plain objects", () => {
    expect(isObject({})).to.be.true;
    expect(isObject({ a: 1 })).to.be.true;
  });

  it("should return false for null", () => {
    expect(isObject(null)).to.be.false;
  });

  it("should return false for arrays", () => {
    expect(isObject([])).to.be.true;
  });

  it("should return false for primitives", () => {
    expect(isObject(123)).to.be.false;
    expect(isObject("string")).to.be.false;
    expect(isObject(true)).to.be.false;
  });
});

import { expect } from "chai";
import slice from "../src/slice.js";

describe("slice", () => {
  const array = [1, 2, 3, 4];

  it("should return a slice from start index to end of array", () => {
    expect(slice(array, 2)).to.deep.equal([3, 4]);
  });

  it("should return a slice from start to end index", () => {
    expect(slice(array, 1, 3)).to.deep.equal([2, 3]);
  });

  it("should handle negative start index", () => {
    expect(slice(array, -2)).to.deep.equal([3, 4]);
  });

  it("should handle negative end index", () => {
    expect(slice(array, 1, -1)).to.deep.equal([2, 3]);
  });

  it("should return empty array if start >= end", () => {
    expect(slice(array, 3, 2)).to.deep.equal([]);
  });

  it("should handle empty array", () => {
    expect(slice([], 0, 2)).to.deep.equal([]);
  });

  it("should handle undefined start and end", () => {
    expect(slice(array)).to.deep.equal([1, 2, 3, 4]);
  });

  it("should handle start index larger than array length", () => {
    expect(slice(array, 10)).to.deep.equal([]);
  });

  it("should handle end index larger than array length", () => {
    const result = slice(array, 1, 10).filter((x) => x !== undefined);
    expect(result).to.deep.equal([2, 3, 4]);
  });
});

import { expect } from "chai";
import upperFirst from "../src/upperFirst.js";

describe("upperFirst", () => {
  it("should capitalize the first letter of a lowercase string", () => {
    expect(upperFirst("fred")).to.equal("Fred");
  });

  it("should leave the first letter capitalized if already uppercase", () => {
    expect(upperFirst("Fred")).to.equal("Fred");
  });

  it("should handle an empty string", () => {
    expect(upperFirst("")).to.equal("");
  });

  it("should not change the rest of the string", () => {
    expect(upperFirst("fRED")).to.equal("FRED");
  });

  it("should handle single character strings", () => {
    expect(upperFirst("a")).to.equal("A");
  });
});
